e="alunos[<?=e($a['id'])?>][observacao]"><?=e($x['observacao']??'')?></textarea></label></details><?php endforeach;?></div><label>Dificuldades gerais<textarea name="dificuldades_gerais"><?=e($report['dificuldades_gerais'])?></textarea></label><label>Medidas adotadas<textarea name="medidas_adotadas"><?=e($report['medidas_adotadas'])?></textarea></label><label>Observações<textarea name="observacoes_professor"><?=e($report['observacoes_professor'])?></textarea></label><?php if($_SESSION['user']['perfil']==='PROFESSOR'&&in_array($report['status'],['PENDENTE','RASCUNHO','DEVOLVIDO'],true)):?><div class="actions"><button name="acao" value="rascunho">Salvar rascunho</button><button name="acao" value="enviar" class="primary">Enviar para conferência</button></div><?php endif;?></form><?php if($_SESSION['user']['perfil']!=='PROFESSOR'&&$report['status']==='ENVIADO'):?><form method="post" action="/coordenacao/relatorios/<?=e($report['id'])?>"><input type="hidden" name="_csrf" value="<?=e(Csrf::token())?>"><label>Parecer<textarea name="parecer"></textarea></label><label>Justificativa da devolução<textarea name="justificativa"></textarea></label><button name="acao" value="devolver">Devolver</button><button name="acao" value="aprovar" data-confirm="Confirma a aprovação?">Aprovar</button></form><?php endif;?><section><h2>Histórico</h2><ul><?php foreach($history as$h):?><li><?=e($h['criado_em'])?> — <?=e($h['status_anterior'])?> → <?=e($h['status_novo'])?> por <?=e($h['usuario_nome'])?> <?=e($h['justificativa'])?></li><?php endforeach;?></ul></section><?php $content=ob_get_clean();require __DIR__.'/layout.php';
